css = """/* styles.css — Boids Simulation
   - Full-window canvas
   - Floating controls panel with play/pause button, boid count slider, and status
   - Lightweight, readable, and responsive
*/

/* Reset / base */
html, body {
  height: 100%;
  margin: 0;
  padding: 0;
  box-sizing: border-box;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
  background: linear-gradient(180deg, #071026 0%, #04111a 60%);
  color: #e7f2ff;
  overflow: hidden; /* keep canvas full-window without scrollbars */
  line-height: 1;
}

/* Full-window canvas */
canvas#canvas {
  display: block;
  position: fixed;
  inset: 0; /* top:0; right:0; bottom:0; left:0; */
  width: 100%;
  height: 100%;
  background: transparent; /* simulation draws on canvas */
  touch-action: none; /* avoid browser gestures interfering */
}

/* Controls panel (floating) */
.controls {
  position: fixed;
  top: 14px;
  left: 14px;
  display: flex;
  gap: 10px;
  align-items: center;
  background: rgba(6, 12, 20, 0.5);
  color: #e7f2ff;
  padding: 10px 12px;
  border-radius: 10px;
  box-shadow: 0 8px 22px rgba(2,8,18,0.55), inset 0 1px 0 rgba(255,255,255,0.02);
  backdrop-filter: blur(6px) saturate(1.05);
  -webkit-backdrop-filter: blur(6px) saturate(1.05);
  user-select: none;
  z-index: 999;
  min-width: 200px;
}

/* Compact layout variant when space is constrained */
.controls.compact {
  gap: 8px;
  padding: 8px;
  left: 8px;
  top: 8px;
}

/* Button */
.btn {
  appearance: none;
  -webkit-appearance: none;
  border: none;
  padding: 8px 12px;
  border-radius: 8px;
  font-weight: 600;
  cursor: pointer;
  color: #051022;
  background: linear-gradient(180deg, #9be7ff 0%, #4fb3e6 100%);
  box-shadow: 0 6px 12px rgba(24, 88, 136, 0.15);
  transition: transform 120ms ease, box-shadow 120ms ease, opacity 120ms ease;
}
.btn:active { transform: translateY(1px) scale(0.995); }
.btn:hover  { box-shadow: 0 8px 18px rgba(24, 88, 136, 0.22); }
.btn.secondary {
  background: linear-gradient(180deg,#2f3f4f,#213243);
  color: #dbeeff;
  box-shadow: none;
  border: 1px solid rgba(255,255,255,0.03);
}

/* Range slider (boid count) */
.control-group {
  display: flex;
  gap: 8px;
  align-items: center;
}

label {
  font-size: 0.9rem;
  color: #cfe8ff;
  margin-right: 6px;
  white-space: nowrap;
}

/* Visual size of the slider; browsers vary in styling support */
input[type="range"] {
  -webkit-appearance: none;
  width: 180px;
  height: 6px;
  background: linear-gradient(90deg, rgba(255,255,255,0.12), rgba(255,255,255,0.06));
  border-radius: 999px;
  outline: none;
  cursor: pointer;
}

/* Webkit track/thumb */
input[type="range"]::-webkit-slider-runnable-track {
  height: 6px;
  background: linear-gradient(90deg, rgba(255,255,255,0.12), rgba(255,255,255,0.03));
  border-radius: 999px;
}
input[type="range"]::-webkit-slider-thumb {
  -webkit-appearance: none;
  margin-top: -6px; /* center the thumb */
  width: 18px;
  height: 18px;
  background: linear-gradient(180deg, #ffffff, #cfeaff);
  border-radius: 50%;
  box-shadow: 0 4px 10px rgba(0,0,0,0.45);
  border: 2px solid rgba(12,30,45,0.06);
}

/* Firefox thumb/track */
input[type="range"]::-moz-range-track {
  height: 6px;
  background: linear-gradient(90deg, rgba(255,255,255,0.12), rgba(255,255,255,0.03));
  border-radius: 999px;
}
input[type="range"]::-moz-range-thumb {
  width: 18px;
  height: 18px;
  background: #ffffff;
  border-radius: 50%;
  border: none;
}

/* Status display (FPS / count) */
.status {
  display: inline-flex;
  flex-direction: column;
  gap: 2px;
  font-size: 0.85rem;
  text-align: left;
  padding: 8px 10px;
  background: rgba(255,255,255,0.03);
  border-radius: 8px;
  min-width: 100px;
  color: #dff4ff;
}

/* Small subtle separators or hints */
.kv {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  align-items: center;
  font-variant-numeric: tabular-nums;
}

/* Footer-style hint area (optional) */
.hint {
  position: fixed;
  right: 14px;
  bottom: 14px;
  padding: 8px 10px;
  background: rgba(6,12,20,0.45);
  color: #bcdcf8;
  border-radius: 8px;
  font-size: 0.85rem;
  z-index: 998;
}

/* Responsive adjustments */
@media (max-width: 600px) {
  .controls {
    left: 8px;
    top: 8px;
    padding: 8px;
    gap: 6px;
  }
  input[type="range"] { width: 120px; }
  .btn { padding: 6px 8px; font-size: 0.9rem; }
  .status { font-size: 0.8rem; min-width: 80px; }
}

/* Utility helpers (used by script classes) */
.hidden { display: none !important; }
.center {
  position: absolute;
  left: 50%;
  top: 50%;
  transform: translate(-50%, -50%);
}
"""

# Write the file to the required path
path = "./output/boids-simulation/styles.css"
write_file(path, css)

# Quick sanity check: ensure file was written and has expected fragment
content_check = ""
try:
    content_check = open(path, "r", encoding="utf-8").read(2000)
    assert "canvas#canvas" in content_check and ".controls" in content_check
except Exception as e:
    done(f"ERROR writing {path}: {e}")

done(f"Wrote {path}")
